{
  "name": "Senior Health Insurance Counseling for Kansas (SHICK)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to anyone with Medicare questions, including older Kansans, people with disabilities, and caregivers[1][2][4][6]",
    "asset_limits": "No asset limits or tests apply[2][4]",
    "other_requirements": ["Open to all Kansans with questions about Medicare or related health insurance; no affiliation requirement beyond having Medicare-related inquiries[1][2][4][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential, one-on-one counseling on Medicare (Parts A-D), Medicare Supplement (Medigap), Medicare Advantage, prescription drug coverage (Part D), Extra Help, long-term care insurance, claims/appeals, supplemental rate comparisons, employer group plans, Medicaid, and other health insurance options; public education presentations; available Monday-Friday, typically 8:30 a.m.-3 p.m. or 8 a.m.-5 p.m. via phone or in-person[1][2][3][4][5][7][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-860-5260 (statewide toll-free)[2][3][8][9]", "Regional/local contacts (e.g., Sedgwick: 316-660-0126[1], Johnson County: 913-715-8856[5], North Central: 1-800-432-2703[6])", "Website: https://www.kdads.ks.gov/services-programs/aging/medicare-programs/senior-health-insurance-counseling-for-kansas-shick[2][3]", "In-person: Through local Area Agencies on Aging or SHICK counselors statewide[1][5][6][8]", "Mail/Fax: Kansas Department for Aging and Disability Services, 503 S. Kansas Ave, Topeka, KS 66603; Fax: 785-296-0256[3][8]"],
    "processing_time": "Counseling appointments scheduled upon contact; no formal processing as it's direct service, though busy during Open Enrollment (mid-October to early December)[6]",
    "waitlist": "No waitlist mentioned; appointments available via phone[1][2][4][5]",
    "forms": ["No specific forms required; schedule appointment directly[2][4]"],
    "documents": ["Medicare card, current insurance documents, prescription lists recommended for counseling sessions but not mandatory for scheduling[7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of Kansas[2][3][6][7]",
    "regional_variations": "Delivered through local Area Agencies on Aging and volunteer counselors with regional contacts and offices (e.g., Central Plains AAA in Wichita: 800-367-7298 ext. 5132, Wyandotte/Leavenworth AAA in Kansas City: 888-661-1444); no differences in services, but local providers handle appointments[1][5][6][8]",
    "offices_or_providers": ["Kansas Department for Aging and Disability Services, 503 S. Kansas Ave, Topeka, KS 66603[3][8]", "Local examples: Sedgwick County (Wichita)[1], Johnson County[5], North Central region[6]"]
  },
  "official_source": "https://www.kdads.ks.gov/services-programs/aging/medicare-programs/senior-health-insurance-counseling-for-kansas-shick",
  "gotchas": ["Not an insurance provider or sales program—counselors are independent volunteers not affiliated with insurers[1][2][4][8]", "Busy during Medicare Open Enrollment (mid-October to early December), so call early[6]", "Free service, not financial aid or direct healthcare—focuses on education and assistance[2][7]", "Available to anyone with Medicare questions, not just seniors[6]"],
  "data_shape_notes": "no income/asset test; counseling service via statewide volunteer network through Area Agencies on Aging; part of federal SHIP program"
}

{
  "name": "Kansas Senior Nutrition Program (Home-Delivered and Congregate Meals)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits specified; open to all individuals 60+ and spouses. Local providers may have additional criteria—contact them directly.[2]",
    "asset_limits": "No asset limits mentioned.[2]",
    "other_requirements": ["Spouses of individuals 60+ are eligible regardless of age.[2]", "Program volunteers are eligible for congregate meals.[2]", "For home-delivered: Typically requires homebound status or functional impairment, but contact local provider for exact assessment.[2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritious meals in group/congregate settings or home-delivered to residence; nutrition education on food choices, physical activity, and health conditions.[2]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Local Aging and Disability Resource Center at 855-200-ADRC (2372)[2]", "Phone: KDADS at 785-296-0373[2]", "Email: KDADSOAASCA@ks.gov[2]", "Mail: Kansas Department for Aging and Disability Services, Attention: Long Term Services & Supports, 503 S. Kansas Ave., Topeka, KS 66603-3404[2]", "In-person: Local Aging and Disability Resource Center or provider for registration and assessment[2]"],
    "processing_time": "Not specified; varies by local provider.[2]",
    "waitlist": "Possible depending on local capacity; contact provider.[2]",
    "forms": ["No specific form name/number listed; registration via local assessment.[2]"],
    "documents": ["Not explicitly listed; prepare proof of age (e.g., ID) and any income/need details if requested locally.[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None statewide; delivered through local providers.[2]",
    "regional_variations": "Administered by local Aging and Disability Resource Centers (ADRCs) and providers; eligibility details, availability, and wait times may vary by region—contact local ADRC.[2]",
    "offices_or_providers": ["Local Aging and Disability Resource Centers (call 855-200-ADRC)[2]"]
  },
  "official_source": "https://www.kdads.ks.gov/services-programs/aging/kansas-senior-nutrition-program[2]",
  "gotchas": ["No statewide income test, but local providers determine full eligibility including homebound status for delivery—always confirm locally.[2]", "Spouses qualify regardless of age, unlike some programs requiring 60+ for all.[2]", "Funded under Older Americans Act; availability tied to federal/local funding and capacity.[2]", "Distinct from Kansas Senior Farmers Market Nutrition Program, which has strict 185% FPL income limits and provides produce coupons only.[1][3]"],
  "data_shape_notes": "No income or asset limits statewide; priority on age 60+ and spouses; delivered via 15 local Area Agencies on Aging with potential regional capacity differences; requires local assessment for home-delivered."
}

{
  "name": "Caregiver Support Programs",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income or asset limits mentioned in sources; eligibility often tied to Medicaid waivers requiring nursing facility level of care. General KanCare guidelines exist but not detailed for caregivers.[4]",
    "asset_limits": "Not specified; no asset tests detailed for caregiver support programs.[1][2]",
    "other_requirements": ["Caregivers of individuals 60+ or grandparents 60+ caring for grandchildren under 18.[2]", "Family member or informal caregiver 18+ providing care, often for those meeting nursing facility level of care (e.g., frail elderly 65+, physical disabilities 16-64, I/DD 5+).[1]", "For K-RAD: Care for individual with probable Alzheimer's/dementia, limited access to other supports.[5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Respite care, personal care, homemaker services, support services; K-RAD subsidizes up to $1,000/year per care recipient for respite (paid to provider).[5][6] Specifics vary by waiver (e.g., HCBS for frail elderly).[1]",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Phone: Kansas Aging and Disability Resource Center at 1-855-200-2372 (ADRC).[7][8]", "Email for K-RAD: donalds@eckaaa.org with two required forms (not named).[5]", "Contact local Area Agency on Aging, e.g., Northeast Kansas (nekaaa.org), East Central (785-242-7200).[2][5]"],
    "processing_time": "K-RAD: Processed in order received; funds first-come, first-served (fiscal year July-June).[5]",
    "waitlist": "Funding limited, no awards guaranteed; potential wait if funds exhausted.[5]",
    "forms": ["Two unnamed forms for K-RAD.[5]"],
    "documents": ["Not explicitly listed; may include proof of caregiver status, care recipient diagnosis (e.g., Alzheimer's for K-RAD), background check for paid roles.[1][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Varies by county and Area Agency on Aging; targeted to frail elderly, disabilities.[1][6]",
    "regional_variations": "Administered by local Area Agencies on Aging (e.g., Northeast Kansas AAA, East Central AAA); services, providers, funding availability differ by region.[2][5][6]",
    "offices_or_providers": ["Northeast Kansas Area Agency on Aging (nekaaa.org).[2]", "East Central Area Agency on Aging (eckaaa.org, 785-242-7200).[5]", "Kansas Aging and Disability Resource Center (statewide referrals).[8]"]
  },
  "official_source": "https://www.kdads.ks.gov/services-programs/aging/caregivers",
  "gotchas": ["Not a single program but network of waivers (e.g., Frail Elderly, I/DD) and local AAA services; requires nursing facility level of care determination.[1]", "Funding limited (e.g., K-RAD $1,000 cap, first-come).[5]", "Often requires enrollment in Medicaid/KanCare; spouses/family may qualify but need to live with care recipient and pass checks.[1]", "Varies county-to-county; contact local AAA essential.[6]"],
  "data_shape_notes": "Decentralized by Area Agencies on Aging and waivers; no uniform income/asset tables; ties to Medicaid level of care; regional providers and limited funding pools."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents and prospective residents of long-term care facilities regardless of financial status[1][4][5]",
    "asset_limits": "No asset limits or tests apply[1][4]",
    "other_requirements": ["Must be a resident (or prospective resident) of a long-term care facility in Kansas, including nursing homes, assisted living facilities, board and care homes, home plus facilities, adult day care centers, or residential healthcare facilities[4][5][7]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Identify, investigate, and resolve complaints; provide information on long-term care services and resident rights; advocate for improvements in quality of life and care; represent interests before agencies; ensure access to services; handle issues from daily care to food service while protecting privacy and confidentiality[1][3][4][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-877-662-8362 or local (785) 296-3017[1][6]", "Email: LTCO@ks.gov[1]", "Website: https://www.ombudsman.ks.gov to find regional ombudsman or submit concerns[1][6][8]", "In-person: Contact regional ombudsman offices via https://www.ombudsman.ks.gov/find-your-ombudsman[8]"],
    "processing_time": "Not specified; services provided as needed without formal processing[1][3]",
    "waitlist": null,
    "forms": ["No formal application or forms required for residents/families to receive services; contact directly to report concerns[1]"],
    "documents": ["No specific documents needed; provide details of the concern or complaint[1][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services focused on long-term care facilities across Kansas; available statewide[4][6][8]",
    "regional_variations": "Delivered through regional ombudsman offices with local contacts, supervision, and training; find specific office via program website[1][8]",
    "offices_or_providers": ["State office: 900 SW Jackson Street, Suite 1041, Topeka, KS 66612[5]"]
  },
  "official_source": "https://www.ombudsman.ks.gov[8]",
  "gotchas": ["Not a financial aid or direct service program—provides advocacy only, not healthcare, housing, or payments[1][3][4]", "Distinct from KanCare Ombudsman, which handles Medicaid issues[4]", "Anyone can contact (residents, families, staff, community members)—no 'qualification' process[4][5]", "Volunteering requires training and checks, but receiving services does not[1]"],
  "data_shape_notes": "no income test; advocacy services only for long-term care facility residents; regional delivery model; open to all without application"
}

{
  "name": "Senior Care Act Services",
  "eligibility": {
    "age": 60,
    "income_limits": "Adjusted annually in July; exact dollar amounts not specified in available data but based on income and assets via sliding fee scale. No full table by household size provided.",
    "asset_limits": "Evaluated alongside income for sliding fee scale; specific limits or exemptions not detailed. Services cost shared based on ability to pay, ranging from donation to 100% of cost.",
    "other_requirements": [
      "Kansas resident",
      "Meet SCA functional threshold score based on functional assessment (evaluates ADLs like toileting/bathing, IADLs like meal prep/shopping, and cognitive deficits)",
      "Functional limitations in self-care and independent living but able to reside in community with services"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "In-home services including attendant care, respite care, homemaker, chore services, adult day care; plan of care developed post-assessment; self-direction allowed for attendant care or homemaker (can choose family/friend as caregiver); provided on sliding fee scale.",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Phone: Contact local Area Agency on Aging (AAA) at 855-200-2372 for services in your area",
      "In-person: Through one of 11 AAAs or local providers (e.g., Clay County via North Central Flint Hills AAA)"
    ],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": [],
    "documents": [
      "Income and asset documentation for sliding fee determination",
      "Information for functional assessment (no specific list provided)"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Services vary by county; administered through 11 Area Agencies on Aging (AAAs) with local case management and direct service providers (e.g., Wyandotte-Leavenworth AAA, North Central Flint Hills AAA); different providers and service availability per region.",
    "offices_or_providers": [
      "11 AAAs across Kansas, contact 855-200-2372 for local AAA"
    ]
  },
  "official_source": "https://www.kdads.ks.gov/services-programs/aging/senior-care-act-sca",
  "gotchas": [
    "Services are not free—sliding fee scale based on income/assets (donation to 100% cost); not entitlement program",
    "Functional assessment required to qualify; dementia diagnosis alone insufficient",
    "Varies significantly by county/AAA—must contact local AAA for exact services available",
    "Early intervention focus, not long-term like Medicaid waivers; self-pay portion common",
    "Income guidelines change annually in July"
  ],
  "data_shape_notes": "Administered regionally via 11 AAAs with county-specific services and providers; sliding fee scale ties benefits to income/assets; functional assessment drives plan of care; self-direction option unique for family/friend caregivers"
}
